import{_ as t,o as a,c as r,ag as s}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"raspap-webgui","description":"","frontmatter":{},"headers":[],"relativePath":"microcontrollers-and-socs/raspberry-pi/raspberry-pi-hotspot/raspap-webgui.md","filePath":"microcontrollers-and-socs/raspberry-pi/raspberry-pi-hotspot/raspap-webgui.md"}'),i={name:"microcontrollers-and-socs/raspberry-pi/raspberry-pi-hotspot/raspap-webgui.md"};function o(n,e,l,p,d,c){return a(),r("div",null,[...e[0]||(e[0]=[s(`<h1 id="raspap-webgui" tabindex="-1">raspap-webgui <a class="header-anchor" href="#raspap-webgui" aria-label="Permalink to &quot;raspap-webgui&quot;">​</a></h1><p><img src="https://i.imgur.com/xeKD93p.png" alt=""> <a href="https://github.com/raspap/raspap-webgui/releases" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/release-v2.9.2-green" alt="Release 2.9.2"></a> <a href="https://github.com/thibmaek/awesome-raspberry-pi" target="_blank" rel="noreferrer"><img src="https://awesome.re/badge.svg" alt="Awesome"></a> <a href="https://github.com/sponsors/RaspAP" target="_blank" rel="noreferrer"><img src="https://img.shields.io/static/v1?label=Join%20Insiders&amp;message=%E2%9D%A4&amp;logo=GitHub&amp;color=ff69b4" alt="Join Insiders"></a> <a href="https://app.travis-ci.com/RaspAP/raspap-webgui" target="_blank" rel="noreferrer"><img src="https://app.travis-ci.com/RaspAP/raspap-webgui.svg?branch=master" alt="Build Status"></a> <a href="https://crowdin.com/project/raspap" target="_blank" rel="noreferrer"><img src="https://badges.crowdin.net/raspap/localized.svg" alt="Crowdin"></a> <a href="https://twitter.com/rasp_ap" target="_blank" rel="noreferrer"><img src="https://img.shields.io/twitter/url?label=%40RaspAP&amp;logoColor=%23d8224c&amp;url=https%3A%2F%2Ftwitter.com%2Frasp_ap" alt="Twitter URL"></a> <a href="https://www.reddit.com/r/RaspAP/" target="_blank" rel="noreferrer"><img src="https://img.shields.io/reddit/subreddit-subscribers/RaspAP?style=social" alt="Subreddit subscribers"></a></p><p>RaspAP is feature-rich wireless router software that <em>just works</em> on many popular Debian-based devices, including the Raspberry Pi. Our popular Quick installer creates a known-good default configuration for all current Raspberry Pis with onboard wireless. A fully responsive, mobile-ready interface gives you control over the relevant services and networking options. Advanced DHCP settings, WireGuard and OpenVPN support, <a href="https://docs.raspap.com/ssl-quick/" target="_blank" rel="noreferrer">SSL certificates</a>, security audits, <a href="https://docs.raspap.com/captive/" target="_blank" rel="noreferrer">captive portal integration</a>, themes and <a href="https://docs.raspap.com/translations/" target="_blank" rel="noreferrer">multilingual options</a> are included.</p><p>RaspAP has been featured on sites such as <a href="http://www.instructables.com/id/Raspberry-Pi-As-Completely-Wireless-Router/" target="_blank" rel="noreferrer">Instructables</a>, <a href="https://blog.adafruit.com/2016/06/24/raspap-wifi-configuration-portal-piday-raspberrypi-raspberry_pi/" target="_blank" rel="noreferrer">Adafruit</a>, <a href="https://www.raspberrypi.org/weekly/commander/" target="_blank" rel="noreferrer">Raspberry Pi Weekly</a> and <a href="https://project-awesome.org/thibmaek/awesome-raspberry-pi" target="_blank" rel="noreferrer">Awesome Raspberry Pi</a> and implemented in countless projects.</p><p>We hope you enjoy using RaspAP as much as we do creating it. Tell us how you use this with <a href="https://github.com/raspap/raspap-awesome" target="_blank" rel="noreferrer">your own projects</a>.</p><p><img src="https://i.imgur.com/uhBFoOB.png" alt=""> <img src="https://i.imgur.com/EiIpdOS.gif" alt=""> <img src="https://i.imgur.com/eCjUS1H.gif" alt=""> <img src="https://i.imgur.com/5FT2BcS.gif" alt=""> <img src="https://i.imgur.com/RKaBFrZ.gif" alt=""></p><h2 id="contents" tabindex="-1">Contents <a class="header-anchor" href="#contents" aria-label="Permalink to &quot;Contents&quot;">​</a></h2><ul><li>Prerequisites</li><li>Quick installer</li><li>Join Insiders</li><li>WireGuard support</li><li>OpenVPN support</li><li>Ad Blocking</li><li>Bridged AP</li><li>Simultaneous AP and Wifi client</li><li>Manual installation</li><li>802.11ac 5GHz support</li><li>Supported operating systems</li><li>Multilingual support</li><li>HTTPS support</li><li>How to contribute</li><li>Reporting issues</li><li>License</li></ul><h3 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h3><p>Start with a clean install of the <a href="https://www.raspberrypi.org/software/operating-systems/#raspberry-pi-os-32-bit" target="_blank" rel="noreferrer">latest release of Raspberry Pi OS (32-bit) Lite</a>. The Raspberry Pi OS desktop and 64-bit beta distros are unsupported.</p><ol><li>Update Raspbian, including the kernel and firmware, followed by a reboot:</li></ol><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sudo apt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">get update</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sudo apt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">get full</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">upgrade</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sudo reboot</span></span></code></pre></div><ol start="2"><li>Set the &quot;WLAN country&quot; option in <code>raspi-config</code>&#39;s <strong>Localisation Options</strong>: <code>sudo raspi-config</code></li><li>If you have a device without an onboard wireless chipset, the <a href="https://www.edimax.com/edimax/merchandise/merchandise_detail/data/edimax/global/wireless_adapters_n150/ew-7811un" target="_blank" rel="noreferrer"><strong>Edimax Wireless 802.11b/g/n nano USB adapter</strong></a> is an excellent option – it&#39;s small, cheap and has good driver support.</li></ol><p>With the prerequisites done, you can proceed with either the Quick installer or Manual installation steps below.</p><h3 id="quick-installer" tabindex="-1">Quick installer <a class="header-anchor" href="#quick-installer" aria-label="Permalink to &quot;Quick installer&quot;">​</a></h3><p>Install RaspAP from your device&#39;s shell prompt:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://install.raspap.com</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p>The <a href="https://docs.raspap.com/quick/" target="_blank" rel="noreferrer">installer</a> will complete the steps in the manual installation (below) for you.</p><p>After the reboot at the end of the installation the wireless network will be configured as an access point as follows:</p><ul><li>IP address: 10.3.141.1 <ul><li>Username: admin</li><li>Password: secret</li></ul></li><li>DHCP range: 10.3.141.50 — 10.3.141.254</li><li>SSID: <code>raspi-webgui</code></li><li>Password: ChangeMe</li></ul><p><strong>Note:</strong> As the name suggests, the Quick Installer is a great way to quickly setup a new AP. However, it does not automagically detect the unique configuration of your system. Best results are obtained by connecting to ethernet (<code>eth0</code>) or as a WiFi client, also known as managed mode, with <code>wlan0</code>. For the latter, refer to <a href="https://docs.raspap.com/faq/#headless" target="_blank" rel="noreferrer">this FAQ</a>. Special instructions for the Pi Zero W are <a href="https://docs.raspap.com/ap-sta/" target="_blank" rel="noreferrer">available here</a>.</p><p>Please <a href="https://docs.raspap.com/issues/" target="_blank" rel="noreferrer">read this</a> before reporting an issue.</p><h3 id="join-insiders" tabindex="-1">Join Insiders <a class="header-anchor" href="#join-insiders" aria-label="Permalink to &quot;Join Insiders&quot;">​</a></h3><p><a href="https://github.com/sponsors/RaspAP/" target="_blank" rel="noreferrer"><img src="https://i.imgur.com/eml7k0b.png" alt=""></a></p><p>RaspAP is free software, but powered by <em>your</em> support. If you find RaspAP useful for your personal or commercial projects, <a href="https://github.com/sponsors/RaspAP/" target="_blank" rel="noreferrer">become an Insider</a> and get early access to <a href="https://docs.raspap.com/insiders/#exclusive-features" target="_blank" rel="noreferrer">exclusive features</a> in the <a href="https://docs.raspap.com/insiders/" target="_blank" rel="noreferrer">Insiders Edition</a>.</p><p>A tangible side benefit of sponsorship is that <strong>Insiders</strong> are able to help <em>steer future development of RaspAP</em>. This is done through Insiders&#39; team access to discussions, feature requests, issues and more in the private GitHub repository.</p><h3 id="wireguard-support" tabindex="-1">WireGuard support <a class="header-anchor" href="#wireguard-support" aria-label="Permalink to &quot;WireGuard support&quot;">​</a></h3><p><img src="https://i.imgur.com/5YDv37e.png" alt=""></p><p>WireGuard® is an extremely simple yet fast and modern VPN that utilizes state-of-the-art cryptography. It aims to be considerably more performant than OpenVPN, and is generally regarded as the most secure, easiest to use, and simplest VPN solution for modern Linux distributions.</p><p>WireGuard may be optionally installed by the <a href="https://docs.raspap.com/quick/" target="_blank" rel="noreferrer">Quick Installer</a>. Once this is done, you can manage local (server) settings, create a peer configuration and control the <code>wg-quick</code> service with RaspAP.</p><p>Details are <a href="https://docs.raspap.com/wireguard/" target="_blank" rel="noreferrer">provided here</a>.</p><h3 id="openvpn-support" tabindex="-1">OpenVPN support <a class="header-anchor" href="#openvpn-support" aria-label="Permalink to &quot;OpenVPN support&quot;">​</a></h3><p><img src="https://i.imgur.com/ta7tCon.png" alt=""></p><p>OpenVPN may be optionally installed by the Quick Installer. Once this is done, you can <a href="https://docs.raspap.com/openvpn/" target="_blank" rel="noreferrer">manage client configurations</a> and the <code>openvpn-client</code> service with RaspAP.</p><p>To configure an OpenVPN client, upload a valid .ovpn file and, optionally, specify your login credentials. RaspAP will store your client configuration and add firewall rules to forward traffic from OpenVPN&#39;s <code>tun0</code> interface to your configured wireless interface.</p><p>See our <a href="https://docs.raspap.com/openvpn/" target="_blank" rel="noreferrer">OpenVPN documentation</a> for more information.</p><h3 id="ad-blocking" tabindex="-1">Ad Blocking <a class="header-anchor" href="#ad-blocking" aria-label="Permalink to &quot;Ad Blocking&quot;">​</a></h3><p>This feature uses DNS blacklisting to block requests for ads, trackers and other undesirable hosts. To enable ad blocking, simply respond to the prompt during the installation. As a beta release, we encourage testing and feedback from users of RaspAP.</p><p>Details are <a href="https://docs.raspap.com/adblock/" target="_blank" rel="noreferrer">provided here</a>.</p><h3 id="bridged-ap" tabindex="-1">Bridged AP <a class="header-anchor" href="#bridged-ap" aria-label="Permalink to &quot;Bridged AP&quot;">​</a></h3><p>By default RaspAP configures a routed AP for your clients to connect to. A bridged AP configuration is also possible. Slide the <strong>Bridged AP mode</strong> toggle under the <strong>Advanced</strong> tab of <strong>Configure hotspot</strong>, then save and restart the hotspot.</p><p><strong>Note:</strong> In bridged mode, all routing capabilities are handled by your upstream router. Because your router assigns IP addresses to your device&#39;s hotspot and its clients, you might not be able to reach the RaspAP web interface from the default <code>10.3.141.1</code> address. Instead use your RPi&#39;s hostname followed by <code>.local</code> to access the RaspAP web interface. With Raspbian default settings, this should look like <code>raspberrypi.local</code>. Alternate methods are <a href="https://www.raspberrypi.org/documentation/remote-access/ip-address.md" target="_blank" rel="noreferrer">discussed here</a>.</p><p>More information on Bridged AP mode is provided <a href="https://docs.raspap.com/bridged/" target="_blank" rel="noreferrer">in our documentation</a>.</p><h3 id="simultaneous-ap-and-wifi-client" tabindex="-1">Simultaneous AP and Wifi client <a class="header-anchor" href="#simultaneous-ap-and-wifi-client" aria-label="Permalink to &quot;Simultaneous AP and Wifi client&quot;">​</a></h3><p>RaspAP lets you create an AP with a Wifi client configuration, often called <a href="https://docs.raspap.com/ap-sta/" target="_blank" rel="noreferrer">AP-STA mode</a>. With your system configured in managed mode, enable the AP from the <strong>Advanced</strong> tab of <strong>Configure hotspot</strong> by sliding the <strong>Wifi client AP mode</strong> toggle. Save settings and start the hotspot. The managed mode AP is functional without restart.</p><p><strong>Note:</strong> This option is disabled until you configure your system as a wireless client. For a device operating in <a href="https://docs.raspap.com/faq/#headless" target="_blank" rel="noreferrer">managed mode</a> without an <code>eth0</code> connection, this configuration must be enabled <a href="https://docs.raspap.com/ap-sta/" target="_blank" rel="noreferrer"><em>before</em> a reboot</a>.</p><h3 id="manual-installation" tabindex="-1">Manual installation <a class="header-anchor" href="#manual-installation" aria-label="Permalink to &quot;Manual installation&quot;">​</a></h3><p>Detailed manual setup instructions are provided <a href="https://docs.raspap.com/manual/" target="_blank" rel="noreferrer">on our documentation site</a>.</p><h3 id="_802-11ac-5ghz-support" tabindex="-1">802.11ac 5GHz support <a class="header-anchor" href="#_802-11ac-5ghz-support" aria-label="Permalink to &quot;802.11ac 5GHz support&quot;">​</a></h3><p>RaspAP provides an 802.11ac wireless mode option for supported hardware (currently the RPi 3B+/4 and compatible Orange Pi models) and wireless regulatory domains. See <a href="https://docs.raspap.com/faq/#80211ac" target="_blank" rel="noreferrer">this FAQ</a> for more information.</p><h3 id="supported-operating-systems" tabindex="-1">Supported operating systems <a class="header-anchor" href="#supported-operating-systems" aria-label="Permalink to &quot;Supported operating systems&quot;">​</a></h3><p>RaspAP was originally made for Raspbian, but now also installs on the following Debian-based distros.</p><table tabindex="0"><thead><tr><th>Distribution</th><th style="text-align:center;">Release</th><th style="text-align:center;">Architecture</th><th style="text-align:center;">Support</th></tr></thead><tbody><tr><td>Raspberry Pi OS</td><td style="text-align:center;">(32-bit) Lite Bullseye</td><td style="text-align:center;">ARM</td><td style="text-align:center;">Official</td></tr><tr><td>Raspberry Pi OS</td><td style="text-align:center;">(64-bit) Lite Bullseye</td><td style="text-align:center;">ARM</td><td style="text-align:center;">Official</td></tr><tr><td>Armbian</td><td style="text-align:center;">Bullseye</td><td style="text-align:center;"><a href="https://docs.armbian.com/#supported-socs" target="_blank" rel="noreferrer">ARM</a></td><td style="text-align:center;">Official</td></tr><tr><td>Debian</td><td style="text-align:center;">Bullseye</td><td style="text-align:center;">ARM / x86_64</td><td style="text-align:center;">Beta</td></tr><tr><td>Ubuntu</td><td style="text-align:center;">18.04 LTS / 19.10</td><td style="text-align:center;">ARM / x86_64</td><td style="text-align:center;">Beta</td></tr></tbody></table><p><img src="https://i.imgur.com/luiyYNw.png" alt=""></p><p>We find Armbian particularly well-suited for this project. Please note that &quot;supported&quot; is not a guarantee. If you are able to improve support for your preferred distro, we encourage you to actively contribute to the project.</p><h3 id="multilingual-support" tabindex="-1">Multilingual support <a class="header-anchor" href="#multilingual-support" aria-label="Permalink to &quot;Multilingual support&quot;">​</a></h3><p>RaspAP uses <a href="https://www.gnu.org/software/gettext/" target="_blank" rel="noreferrer">GNU Gettext</a> to manage multilingual messages. In order to use RaspAP with one of our supported translations, you must configure a corresponding language package on your RPi. To list languages currently installed on your system, use <code>locale -a</code> at the shell prompt. To generate new locales, run <code>sudo dpkg-reconfigure locales</code> and select any other desired locales. Details are provided on our <a href="https://docs.raspap.com/translations/" target="_blank" rel="noreferrer">documentation site</a>.</p><p>See this list of <a href="https://docs.raspap.com/translations/#supported-languages" target="_blank" rel="noreferrer">supported languages</a> that are actively maintained by volunteer translators. If your language is not supported, why not <a href="https://docs.raspap.com/translations/#contributing-to-a-translation" target="_blank" rel="noreferrer">contribute a translation</a>? Contributors will receive credit as the original translators.</p><h3 id="https-support" tabindex="-1">HTTPS support <a class="header-anchor" href="#https-support" aria-label="Permalink to &quot;HTTPS support&quot;">​</a></h3><p>The Quick Installer may be used to <a href="https://docs.raspap.com/ssl-quick/" target="_blank" rel="noreferrer">generate SSL certificates</a> with <code>mkcert</code>. The installer automates the manual steps <a href="https://docs.raspap.com/ssl-manual/" target="_blank" rel="noreferrer">described here</a>, including configuring lighttpd with SSL support.</p><p>Simply append the <code>-c</code> or <code>--cert</code> option to the Quick Installer, like so:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://install.raspap.com</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cert</span></span></code></pre></div><p><strong>Note</strong>: this only installs mkcert and generates an SSL certificate with the input you provide. It does <em>not</em> (re)install RaspAP.</p><p>More information on SSL certificates and HTTPS support is available <a href="https://docs.raspap.com/ssl-quick/" target="_blank" rel="noreferrer">in our documentation</a>.</p><h3 id="how-to-contribute" tabindex="-1">How to contribute <a class="header-anchor" href="#how-to-contribute" aria-label="Permalink to &quot;How to contribute&quot;">​</a></h3><ol><li>Fork the project in your account and create a new branch: <code>your-great-feature</code>.</li><li>Open an issue in the repository describing the feature contribution you&#39;d like to make.</li><li>Commit changes in your feature branch.</li><li>Open a pull request and reference the initial issue in the pull request message.</li></ol><p>Find out more about our coding style guidelines and recommended tools.</p><h3 id="reporting-issues" tabindex="-1">Reporting issues <a class="header-anchor" href="#reporting-issues" aria-label="Permalink to &quot;Reporting issues&quot;">​</a></h3><p>Please <a href="https://docs.raspap.com/issues/" target="_blank" rel="noreferrer">read this</a> before reporting a bug.</p><h3 id="contributors" tabindex="-1">Contributors <a class="header-anchor" href="#contributors" aria-label="Permalink to &quot;Contributors&quot;">​</a></h3><h4 id="code-contributors" tabindex="-1">Code Contributors <a class="header-anchor" href="#code-contributors" aria-label="Permalink to &quot;Code Contributors&quot;">​</a></h4><p>This project exists thanks to all the awesome people who contribute their time and expertise.</p><p><a href="https://github.com/raspap/raspap-webgui/graphs/contributors" target="_blank" rel="noreferrer"><img src="https://opencollective.com/raspap/contributors.svg?width=890&amp;button=false" alt=""></a></p><h4 id="financial-contributors" tabindex="-1">Financial Contributors <a class="header-anchor" href="#financial-contributors" aria-label="Permalink to &quot;Financial Contributors&quot;">​</a></h4><p>Development of RaspAP is made possible thanks to a sponsorware release model. This means that new features are first exclusively released to sponsors as part of <a href="https://github.com/sponsors/RaspAP" target="_blank" rel="noreferrer"><strong>Insiders</strong></a>.</p><p>Learn more about <a href="https://docs.raspap.com/insiders/#how-sponsorship-works" target="_blank" rel="noreferrer">how sponsorship works</a>, and how easy it is to get access to Insiders.</p><h3 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h3><p>See the LICENSE file.</p>`,78)])])}const g=t(i,[["render",o]]);export{u as __pageData,g as default};
